import{_ as o,c as t,o as i,a1 as a}from"./chunks/framework.DILC4Csi.js";const h=JSON.parse('{"title":"Advanced Workflows: Subagent-Driven Development & Code Reviews","description":"Master Superpowers advanced workflows: subagent-driven development, code reviews, Git worktrees, parallel agents. Boost efficiency with rapid iteration and high-quality delivery.","frontmatter":{"title":"Advanced Workflows: Subagent-Driven Development & Code Reviews","sidebarTitle":"Advanced Workflows","subtitle":"Advanced Development Workflows","description":"Master Superpowers advanced workflows: subagent-driven development, code reviews, Git worktrees, parallel agents. Boost efficiency with rapid iteration and high-quality delivery.","order":150},"headers":[],"relativePath":"obra/superpowers/advanced/index.md","filePath":"obra/superpowers/advanced/index.md"}'),r={name:"obra/superpowers/advanced/index.md"};function n(l,e,s,d,c,p){return i(),t("div",null,[...e[0]||(e[0]=[a('<h1 id="advanced-workflows" tabindex="-1">Advanced Workflows <a class="header-anchor" href="#advanced-workflows" aria-label="Permalink to &quot;Advanced Workflows&quot;">​</a></h1><p>This chapter explains Superpowers&#39; advanced workflows and techniques to help you achieve more efficient and professional development processes. Core content covers subagent-driven development, code review workflows, environment isolation, parallel scheduling, and comprehensive development workflow best practices.</p><h2 id="sub-page-navigation" tabindex="-1">Sub-Page Navigation <a class="header-anchor" href="#sub-page-navigation" aria-label="Permalink to &quot;Sub-Page Navigation&quot;">​</a></h2><h3 id="subagent-driven-development-rapid-iteration-for-multiple-tasks" tabindex="-1"><a href="./../subagent-development/">Subagent-Driven Development</a>: Rapid Iteration for Multiple Tasks <a class="header-anchor" href="#subagent-driven-development-rapid-iteration-for-multiple-tasks" aria-label="Permalink to &quot;[Subagent-Driven Development](../subagent-development/): Rapid Iteration for Multiple Tasks&quot;">​</a></h3><p>Leverage subagents to enable rapid iterative development across multiple independent tasks, executing two-stage automated reviews (spec compliance + code quality), avoiding context pollution, automating TDD workflows, and code review checkpoints.</p><h3 id="code-review-workflow-establish-review-habits" tabindex="-1"><a href="./../code-review-workflow/">Code Review Workflow</a>: Establish Review Habits <a class="header-anchor" href="#code-review-workflow-establish-review-habits" aria-label="Permalink to &quot;[Code Review Workflow](../code-review-workflow/): Establish Review Habits&quot;">​</a></h3><p>Establish early, frequent code review habits, actively requesting code reviews at each development stage. Learn how to properly handle review feedback, prioritize feedback, conduct technical validation, and maintain code quality baselines.</p><h3 id="git-worktree-isolation-isolated-development-environment" tabindex="-1"><a href="./../git-worktrees/">Git Worktree Isolation</a>: Isolated Development Environment <a class="header-anchor" href="#git-worktree-isolation-isolated-development-environment" aria-label="Permalink to &quot;[Git Worktree Isolation](../git-worktrees/): Isolated Development Environment&quot;">​</a></h3><p>Use Git worktrees to create isolated development environments while keeping the main branch clean. Learn directory selection priorities, security verification workflows, project setup, and test baseline validation, achieving concurrently safe development processes.</p><h3 id="parallel-agent-dispatch-3x-speed-bug-fixes" tabindex="-1"><a href="./../parallel-agents/">Parallel Agent Dispatch</a>: 3x Speed Bug Fixes <a class="header-anchor" href="#parallel-agent-dispatch-3x-speed-bug-fixes" aria-label="Permalink to &quot;[Parallel Agent Dispatch](../parallel-agents/): 3x Speed Bug Fixes&quot;">​</a></h3><p>When facing multiple independent challenges, concurrently dispatch multiple subagents to achieve 3x efficiency gains. Learn independent domain identification, focused task creation, parallel dispatch, and review integration, applicable to scenarios like multiple test failures and multi-subsystem issues.</p><h3 id="branch-completion-workflow-graceful-development-conclusion" tabindex="-1"><a href="./../branch-completion/">Branch Completion Workflow</a>: Graceful Development Conclusion <a class="header-anchor" href="#branch-completion-workflow-graceful-development-conclusion" aria-label="Permalink to &quot;[Branch Completion Workflow](../branch-completion/): Graceful Development Conclusion&quot;">​</a></h3><p>Systematically handle development branch completion, including test validation, branch merging, PR creation, and Git worktree cleanup. Learn how to gracefully conclude development and avoid residual issues.</p><h3 id="complete-development-workflow-practice-from-design-to-deployment" tabindex="-1"><a href="./../complete-workflow/">Complete Development Workflow Practice</a>: From Design to Deployment <a class="header-anchor" href="#complete-development-workflow-practice-from-design-to-deployment" aria-label="Permalink to &quot;[Complete Development Workflow Practice](../complete-workflow/): From Design to Deployment&quot;">​</a></h3><p>Integrate all Superpowers skills, demonstrating a comprehensive seven-step development workflow from requirements analysis to feature deployment. Through practical scenarios, learn how to apply core skills like brainstorming, TDD, and code reviews in real projects.</p><h2 id="learning-path-recommendations" tabindex="-1">Learning Path Recommendations <a class="header-anchor" href="#learning-path-recommendations" aria-label="Permalink to &quot;Learning Path Recommendations&quot;">​</a></h2><p>We recommend studying the chapter content in the following order:</p><ol><li><p><strong>Subagent-Driven Development</strong> (Essential)</p><ul><li>This is the core skill of advanced workflows</li><li>Multiple subsequent courses depend on this</li></ul></li><li><p><strong>Code Review Workflow</strong> (Recommended)</p><ul><li>Establish good review habits</li><li>Use together with subagent-driven development</li></ul></li><li><p><strong>Git Worktree Isolation</strong> (Highly Recommended)</p><ul><li>Create safe development environments</li><li>Avoid main branch pollution</li></ul></li><li><p><strong>Parallel Agent Dispatch</strong> (Optional)</p><ul><li>Boost efficiency in specific scenarios</li><li>Requires familiarity with subagent-driven development</li></ul></li><li><p><strong>Branch Completion Workflow</strong> (Recommended)</p><ul><li>Standardize development conclusion workflows</li><li>Use together with other advanced skills</li></ul></li><li><p><strong>Complete Development Workflow Practice</strong> (Comprehensive Practice)</p><ul><li>Synthesize all skills</li><li>Recommended as the final learning step</li></ul></li></ol><div class="tip custom-block"><p class="custom-block-title">Learning Tips</p><ul><li><strong>Progressive Learning</strong>: We recommend studying in course order, each skill builds on previous knowledge</li><li><strong>Practice-Focused</strong>: Advanced workflows require extensive practice, don&#39;t just read without doing</li><li><strong>Context-Aware</strong>: Choose the skills most relevant to your actual project needs for deeper learning ::</li></ul><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><p>To learn this chapter, you should have completed the following foundational content:</p><ul><li>✅ <strong>Core Workflows</strong> (<a href="./../../core-workflows/">core-workflows</a>): <ul><li><a href="./../../core-workflows/design-workflow/">Design Workflow: Brainstorming</a></li><li><a href="./../../core-workflows/planning-workflow/">Planning Workflow: Writing Plans</a></li><li><a href="./../../core-workflows/tdd-workflow/">Test-Driven Development: TDD Rules</a></li><li><a href="./../../core-workflows/debugging-workflow/">Debugging Workflow: Systematic Debugging</a></li><li><a href="./../../core-workflows/verification-workflow/">Verification Workflow: Evidence First</a></li></ul></li></ul><div class="warning custom-block"><p class="custom-block-title">Why Are Prerequisites Required?</p><p>Advanced workflows build upon core workflows. Without the foundation, advanced techniques may not be correctly applied or could lead to issues. We recommend completing core workflow learning first. ::</p><h2 id="applicable-scenarios" tabindex="-1">Applicable Scenarios <a class="header-anchor" href="#applicable-scenarios" aria-label="Permalink to &quot;Applicable Scenarios&quot;">​</a></h2><p>The advanced workflows in this chapter apply to the following scenarios:</p><table tabindex="0"><thead><tr><th>Scenario</th><th>Recommended Course</th></tr></thead><tbody><tr><td>Need to complete multiple independent tasks quickly</td><td><a href="./../subagent-development/">Subagent-Driven Development</a></td></tr><tr><td>Team collaboration requires code reviews</td><td><a href="./../code-review-workflow/">Code Review Workflow</a></td></tr><tr><td>Need to work on multiple development tasks simultaneously</td><td><a href="./../git-worktrees/">Git Worktree Isolation</a></td></tr><tr><td>Encounter multiple independent bugs or issues</td><td><a href="./../parallel-agents/">Parallel Agent Dispatch</a></td></tr><tr><td>Need standardized branch management</td><td><a href="./../branch-completion/">Branch Completion Workflow</a></td></tr><tr><td>Want to master the complete development process</td><td><a href="./../complete-workflow/">Complete Development Workflow Practice</a></td></tr></tbody></table><h2 id="next-steps-guide" tabindex="-1">Next Steps Guide <a class="header-anchor" href="#next-steps-guide" aria-label="Permalink to &quot;Next Steps Guide&quot;">​</a></h2><p>After completing this chapter, you can:</p><ul><li>📚 <strong>Write Custom Skills</strong>: Learn <a href="./../../extending/writing-skills/">Writing Custom Skills</a> to create Superpowers skills tailored to your needs</li><li>🧪 <strong>Test Your Skills</strong>: Learn <a href="./../../extending/testing-skills/">Testing Skills</a> to verify skill correctness</li><li>🤝 <strong>Contribute to Community</strong>: Learn <a href="./../../extending/contributing/">Contributing Guide</a> to share your skills with the community</li></ul><div class="info custom-block"><p class="custom-block-title">Advanced Path</p><p>The power of Superpowers lies in its extensibility. After completing advanced workflows, we recommend exploring the <a href="./../../extending/">extending</a> chapter to learn how to write and contribute your own skills. ::</p></div></div></div>',19)])])}const m=o(r,[["render",n]]);export{h as __pageData,m as default};
